# Get original model sizes from HF repo tree
curl -sL "https://huggingface.co/api/models/XiaomiMiMo/MiMo-V2.5-ASR/revision/main" 2>/dev/null | python3 -c "
import sys, json
try:
    data = json.load(sys.stdin)
    if isinstance(data, list):
        for f in data:
            if f.get('type') == 'file' and f.get('size'):
                print(f['path'], f['size'])
except:
    print('parse failed')
" 2>/dev/null | head -30

# Try to query HF API for file sizes
curl -sL "https://huggingface.co/api/models/XiaomiMiMo/MiMo-V2.5-ASR" -H "Accept: application/json" 2>/dev/null | python3 -c "
import sys, json
try:
    d = json.load(sys.stdin)
    for k in ['siblings', 'files', 'model_files']:
        if k in d:
            print(k + ':', len(d[k]))
            for f in d[k][:5]:
                if isinstance(f, dict):
                    print(' ', f.get('rfilename', f.get('filename', '?')), f.get('size', '?'))
                    break
            break
    print('keys:', list(d.keys())[:10])
except Exception as e:
    print('error:', e)
"
